#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int x[n], y[n], z[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d %d", &x[i], &y[i], &z[i]);
    }
    int minx = x[0], miny = y[0], minz = z[0];
    int maxx = x[0], maxy = y[0], maxz = z[0];
    for (int i = 1; i < n; i++) {
        if (x[i] < minx) minx = x[i];
        if (y[i] < miny) miny = y[i];
        if (z[i] < minz) minz = z[i];
        if (x[i] > maxx) maxx = x[i];
        if (y[i] > maxy) maxy = y[i];
        if (z[i] > maxz) maxz = z[i];
    }
    printf("%d\n", (maxx - minx + 1) * (maxy - miny + 1) * 6);
    return 0;
}

