code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let x = [], y = [], z = [];
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        let [xi, yi, zi] = input.split(' ').map(Number);
        x.push(xi);
        y.push(yi);
        z.push(zi);
        if (x.length === n) {
            let minx = Math.min(...x), miny = Math.min(...y), minz = Math.min(...z);
            let maxx = Math.max(...x), maxy = Math.max(...y), maxz = Math.max(...z);
            console.log((maxx - minx + 1) * (maxy - miny + 1) * 6);
            rl.close();
        }
    }
});

